// Set the expiration time for the remember me cookie
const rememberMeCookieExpire = 30 * 24 * 60 * 60 * 1000; // 30 days in milliseconds

// Function to set the remember me cookie
function setRememberMeCookie(username, passwordHash) {
    const rememberMeCookie = `${username}:${passwordHash}`;
    document.cookie = `remember_me=${btoa(rememberMeCookie)};expires=${new Date(Date.now() + rememberMeCookieExpire).toUTCString()};path=/`;
}

// Function to get the remember me cookie
function getRememberMeCookie() {
    const cookies = document.cookie.split(';');
    for (let i = 0; i < cookies.length; i++) {
        const cookie = cookies[i].trim();
        if (cookie.startsWith('remember_me=')) {
            return atob(cookie.substring(11));
        }
    }
    return null;
}

// Function to auto-login using the remember me cookie
